import React, { useState, useMemo } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(50);
  const [searchTerm, setSearchTerm] = useState("");

  // Safe data extraction with fallbacks
  const batchResult = dashboardData?.batchResult || {};
  
  // Extract data with proper fallbacks
  const dataset_info = batchResult.dataset_info || {};
  const risk_analysis = batchResult.predictions_summary || {};
  const customer_segmentation = {}; // This might not exist in new structure
  const feature_analysis = batchResult.feature_analysis || {};
  const all_predictions = batchResult.all_predictions || [];
  const data_source = batchResult.data_source || "unknown";
  
  // Risk distribution from new structure
  const riskDistribution = batchResult.risk_distribution || {
    'P1: High Risk (>70%)': 0,
    'P2: Moderate Risk (31-70%)': 0,
    'P3: Low Risk (<=30%)': 0
  };

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers || all_predictions.length || 0;

  // Calculate risk counts from distribution
  const lowRiskCount = riskDistribution['P3: Low Risk (<=30%)'] || 0;
  const mediumRiskCount = riskDistribution['P2: Moderate Risk (31-70%)'] || 0;
  const highRiskCount = riskDistribution['P1: High Risk (>70%)'] || 0;

  // Format display value - replace null/undefined with '-'
  const formatDisplayValue = (value, columnName = '') => {
    if (value === null || value === undefined || value === '' || value === 0) {
      return '-';
    }
    
    // For specific columns that should never show 0
    if (columnName && typeof value === 'number') {
      const columnLower = columnName.toLowerCase();
      if ((columnLower.includes('tenure') || 
           columnLower.includes('ordercount') || 
           columnLower.includes('cashback') || 
           columnLower.includes('satisfaction') || 
           columnLower.includes('hourspend')) && value === 0) {
        return '-';
      }
    }
    
    // Format numbers with commas for better readability
    if (typeof value === 'number') {
      if (columnName.toLowerCase().includes('cashback') || columnName.toLowerCase().includes('amount')) {
        return `₹${value.toLocaleString()}`;
      }
      return value.toLocaleString();
    }
    
    return value;
  };

  // Filter and paginate ALL predictions
  const filteredPredictions = useMemo(() => {
    if (!all_predictions || all_predictions.length === 0) return [];
    
    return all_predictions.filter(customer => {
      if (!searchTerm) return true;
      
      const searchLower = searchTerm.toLowerCase();
      return (
        (customer.Customer_ID && customer.Customer_ID.toString().toLowerCase().includes(searchLower)) ||
        (customer.CustomerID && customer.CustomerID.toString().toLowerCase().includes(searchLower)) ||
        (customer.Risk_Level && customer.Risk_Level.toLowerCase().includes(searchLower)) ||
        (customer.Predicted_Churn && customer.Predicted_Churn.toString().toLowerCase().includes(searchLower))
      );
    });
  }, [all_predictions, searchTerm]);

  // Pagination calculations
  const totalPages = Math.ceil(filteredPredictions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentPredictions = filteredPredictions.slice(startIndex, endIndex);

  // Function to download ALL customer data
  const downloadAllCustomers = async () => {
    try {
      // Show loading state
      const downloadBtn = document.querySelector('.download-all-btn');
      const originalText = downloadBtn.innerHTML;
      downloadBtn.innerHTML = '<div class="spinner-small"></div> Generating Full Report...';
      downloadBtn.disabled = true;

      console.log('Starting download process...');

      // Get the file from the original file input or global variable
      let fileToProcess = null;
      
      // Try to get file from the file input
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
        console.log('File found in file input:', fileToProcess.name);
      } 
      // Try to get from global variable (set during upload)
      else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
        console.log('File found in global variable:', fileToProcess.name);
      }
      // If no file found, show error
      else {
        alert("❌ No CSV file found. Please go back to 'Batch Processing' and upload your CSV file again to download the complete report.");
        downloadBtn.innerHTML = originalText;
        downloadBtn.disabled = false;
        return;
      }

      // Create FormData and append the file
      const formData = new FormData();
      formData.append('file', fileToProcess);

      console.log('Sending request to backend...');

      // Send request to backend
      const response = await fetch('http://localhost:5000/api/batch/download-report', {
        method: 'POST',
        body: formData,
      });

      console.log('Response status:', response.status);

      // Check if response is successful
      if (!response.ok) {
        const errorText = await response.text();
        console.error('Server error response:', errorText);
        
        // Try to parse as JSON if possible
        try {
          const errorJson = JSON.parse(errorText);
          throw new Error(`Server error: ${errorJson.error || errorJson.message || 'Unknown error'}`);
        } catch (e) {
          throw new Error(`HTTP error! status: ${response.status}. Server returned: ${errorText.substring(0, 100)}...`);
        }
      }

      // Check if response is CSV
      const contentType = response.headers.get('content-type');
      console.log('Content-Type:', contentType);
      
      if (!contentType || !contentType.includes('text/csv')) {
        const responseData = await response.text();
        console.error('Unexpected response type. First 200 chars:', responseData.substring(0, 200));
        throw new Error(`Expected CSV but got: ${contentType}. Please check backend server.`);
      }

      // Get the blob data
      const blob = await response.blob();
      console.log('Blob size:', blob.size, 'type:', blob.type);

      if (blob.size === 0) {
        throw new Error('Downloaded file is empty');
      }

      // Create download link
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      
      // Get filename from response headers or create one
      const contentDisposition = response.headers.get('content-disposition');
      let filename = 'churn_analysis_complete_report.csv';
      
      if (contentDisposition) {
        const filenameMatch = contentDisposition.match(/filename="(.+)"/);
        if (filenameMatch) {
          filename = filenameMatch[1];
        }
      }
      
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      console.log('✅ Download completed successfully:', filename);

      // Reset button
      downloadBtn.innerHTML = originalText;
      downloadBtn.disabled = false;

    } catch (error) {
      console.error('❌ Error downloading full report:', error);
      
      let errorMessage = 'Error downloading complete report. ';
      
      if (error.message.includes('Failed to fetch')) {
        errorMessage += 'Cannot connect to server. Please make sure the backend is running on port 5000.';
      } else if (error.message.includes('HTTP error! status: 5')) {
        errorMessage += 'Server error. Please check the backend console for details.';
      } else if (error.message.includes('HTTP error! status: 4')) {
        errorMessage += 'Client error: ' + error.message;
      } else {
        errorMessage += error.message;
      }
      
      alert(errorMessage);
      
      // Reset button on error
      const downloadBtn = document.querySelector('.download-all-btn');
      if (downloadBtn) {
        downloadBtn.innerHTML = '<span class="btn-icon">📥</span> Download Complete Report';
        downloadBtn.disabled = false;
      }
    }
  };

  // Function to download specific risk level customers
  const downloadRiskCustomers = async (riskLevel) => {
    try {
      // Show loading state
      const downloadBtn = document.querySelector(`.download-${riskLevel}-btn`);
      const originalText = downloadBtn.innerHTML;
      downloadBtn.innerHTML = '<div class="spinner-small"></div> Generating Report...';
      downloadBtn.disabled = true;

      console.log(`Starting ${riskLevel} risk customers download process...`);

      // Get the file from the original file input or global variable
      let fileToProcess = null;
      
      // Try to get file from the file input
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
        console.log('File found in file input:', fileToProcess.name);
      } 
      // Try to get from global variable (set during upload)
      else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
        console.log('File found in global variable:', fileToProcess.name);
      }
      // If no file found, show error
      else {
        alert(`❌ No CSV file found. Please go back to 'Batch Processing' and upload your CSV file again to download ${riskLevel} risk customers.`);
        downloadBtn.innerHTML = originalText;
        downloadBtn.disabled = false;
        return;
      }

      // Create FormData and append both file and risk level
      const formData = new FormData();
      formData.append('file', fileToProcess);
      formData.append('risk_level', riskLevel); // Add risk level as form data

      console.log(`Sending ${riskLevel} risk customers request to backend...`);

      // Send request to backend with FormData (not JSON)
      const response = await fetch('http://localhost:5000/api/batch/download-risk-customers', {
        method: 'POST',
        body: formData, // Send as FormData, not JSON
      });

      console.log('Response status:', response.status);

      // Check if response is successful
      if (!response.ok) {
        const errorText = await response.text();
        console.error('Server error response:', errorText);
        
        // Try to parse as JSON if possible
        try {
          const errorJson = JSON.parse(errorText);
          throw new Error(`Server error: ${errorJson.error || errorJson.message || 'Unknown error'}`);
        } catch (e) {
          throw new Error(`HTTP error! status: ${response.status}. Server returned: ${errorText.substring(0, 100)}...`);
        }
      }

      // Check if response is CSV
      const contentType = response.headers.get('content-type');
      console.log('Content-Type:', contentType);
      
      if (!contentType || !contentType.includes('text/csv')) {
        const responseData = await response.text();
        console.error('Unexpected response type. First 200 chars:', responseData.substring(0, 200));
        throw new Error(`Expected CSV but got: ${contentType}. Please check backend server.`);
      }

      // Get the blob data
      const blob = await response.blob();
      console.log('Blob size:', blob.size, 'type:', blob.type);

      if (blob.size === 0) {
        throw new Error('Downloaded file is empty');
      }

      // Create download link
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      
      // Get filename from response headers or create one
      const contentDisposition = response.headers.get('content-disposition');
      let filename = `churn_analysis_${riskLevel}_risk_customers.csv`;
      
      if (contentDisposition) {
        const filenameMatch = contentDisposition.match(/filename="(.+)"/);
        if (filenameMatch) {
          filename = filenameMatch[1];
        }
      }
      
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      console.log(`✅ ${riskLevel} risk customers download completed successfully:`, filename);

      // Reset button
      downloadBtn.innerHTML = originalText;
      downloadBtn.disabled = false;

    } catch (error) {
      console.error(`❌ Error downloading ${riskLevel} risk customers:`, error);
      
      let errorMessage = `Error downloading ${riskLevel} risk customers. `;
      
      if (error.message.includes('Failed to fetch')) {
        errorMessage += 'Cannot connect to server. Please make sure the backend is running on port 5000.';
      } else if (error.message.includes('HTTP error! status: 5')) {
        errorMessage += 'Server error. Please check the backend console for details.';
      } else if (error.message.includes('HTTP error! status: 4')) {
        errorMessage += 'Client error: ' + error.message;
      } else {
        errorMessage += error.message;
      }
      
      alert(errorMessage);
      
      // Reset button on error
      const downloadBtn = document.querySelector(`.download-${riskLevel}-btn`);
      if (downloadBtn) {
        const riskDisplay = riskLevel.charAt(0).toUpperCase() + riskLevel.slice(1);
        downloadBtn.innerHTML = `<span class="btn-icon">📥</span> Download ${riskDisplay} Risk`;
        downloadBtn.disabled = false;
      }
    }
  };

  // Function to handle page change
  const handlePageChange = (newPage) => {
    setCurrentPage(newPage);
  };

  // Function to handle items per page change
  const handleItemsPerPageChange = (e) => {
    setItemsPerPage(Number(e.target.value));
    setCurrentPage(1); // Reset to first page
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <h2>📊 Batch Analysis Dashboard</h2>
        <div className="header-actions">
          <button 
            className="download-report-btn download-all-btn"
            onClick={downloadAllCustomers}
            title="Download complete report with all customers"
          >
            <span className="btn-icon">📥</span>
            Download Complete Report
          </button>
        </div>
      </div>

      {/* Dataset Overview */}
      <div className="section-card dataset-overview">
        <h3>📁 Dataset Overview</h3>
        <div className="dataset-stats-grid">
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_customers || all_predictions.length}</div>
            <div className="stat-label">Total Customers</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_features || 'N/A'}</div>
            <div className="stat-label">Features Analyzed</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.dataset_size_kb ? dataset_info.dataset_size_kb.toFixed(1) : 'N/A'} KB</div>
            <div className="stat-label">Dataset Size</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{risk_analysis.total_predicted_churn || 0}</div>
            <div className="stat-label">Predicted Churn</div>
          </div>
        </div>
        
        <div className="data-source-info">
          <span className="source-label">Data Source:</span>
          <span className="source-value">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
          <span className="source-label" style={{marginLeft: '1rem'}}>Imputation:</span>
          <span className="source-value">Median ML</span>
        </div>
      </div>

      {/* Risk Analysis */}
      <div className="section-card risk-analysis">
        <h3>⚠️ Risk Analysis Summary</h3>
        <div className="risk-metrics-grid">
          <div className="risk-metric">
            <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
            <div className="metric-label">Average Churn Probability</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
            <div className="metric-label">Overall Churn Rate</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{highRiskCount}</div>
            <div className="metric-label">High-Risk Customers</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">₹{((risk_analysis.average_probability || 0) * totalCustomers * 850).toLocaleString()}</div>
            <div className="metric-label">Potential Revenue Loss</div>
          </div>
        </div>

        {/* Risk Distribution */}
        <div className="risk-distribution">
          <h4>Risk Level Distribution</h4>
          <div className="distribution-bars">
            {Object.entries(riskDistribution).map(([riskLevel, count]) => {
              const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
              let barColor = "";
              
              if (riskLevel.includes("High")) barColor = "high-risk";
              else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
              else barColor = "low-risk";

              return (
                <div key={riskLevel} className="distribution-item">
                  <div className="risk-label">{riskLevel}</div>
                  <div className="bar-container">
                    <div 
                      className={`risk-bar ${barColor}`}
                      style={{ width: `${percentage}%` }}
                    >
                      <span className="bar-count">{count} customers</span>
                    </div>
                  </div>
                  <div className="risk-percentage">{percentage}%</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Feature Analysis - Only show if data exists */}
      {feature_analysis && Object.keys(feature_analysis).length > 0 && (
        <div className="section-card feature-analysis">
          <h3>🔍 High-Risk Customer Profile</h3>
          <div className="feature-grid">
            {Object.entries(feature_analysis).slice(0, 6).map(([feature, stats]) => (
              <div key={feature} className="feature-card">
                <div className="feature-name">{feature}</div>
                <div className="feature-stats">
                  <div className="stat">
                    <span className="stat-label">Avg:</span>
                    <span className="stat-value">{(stats.mean || 0).toFixed(2)}</span>
                  </div>
                  <div className="stat">
                    <span className="stat-label">Med:</span>
                    <span className="stat-value">{(stats.median || 0).toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ALL Predictions with Pagination */}
      <div className="section-card all-predictions">
        <div className="predictions-header">
          <h3>👥 All Customer Predictions ({totalCustomers} Total)</h3>
          <div className="predictions-controls">
            <div className="search-box">
              <input
                type="text"
                placeholder="Search customers..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>
            <div className="pagination-controls">
              <select 
                value={itemsPerPage} 
                onChange={handleItemsPerPageChange}
                className="items-per-page-select"
              >
                <option value={20}>20 per page</option>
                <option value={50}>50 per page</option>
                <option value={100}>100 per page</option>
                <option value={200}>200 per page</option>
              </select>
              
              <div className="pagination-info">
                Showing {startIndex + 1}-{Math.min(endIndex, filteredPredictions.length)} of {filteredPredictions.length} customers
              </div>
              
              <div className="pagination-buttons">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="pagination-btn"
                >
                  Previous
                </button>
                <span className="page-info">
                  Page {currentPage} of {totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  className="pagination-btn"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="predictions-table-container">
          <div className="predictions-table">
            <table>
              <thead>
                <tr>
                  <th>Customer ID</th>
                  <th>Churn Probability</th>
                  <th>Risk Level</th>
                  <th>Prediction</th>
                  <th>Tenure</th>
                  <th>Order Count</th>
                  <th>Cashback</th>
                  <th>Days Since Last Order</th>
                  <th>Satisfaction</th>
                </tr>
              </thead>
              <tbody>
                {currentPredictions.map((customer, index) => {
                  const riskLevel = customer.Risk_Level || 'Unknown';
                  const churnProbability = customer.Churn_Probability || 0;
                  
                  return (
                    <tr key={index}>
                      <td className="customer-id">
                        {customer.Customer_ID || customer.CustomerID || `CUST_${startIndex + index + 1}`}
                      </td>
                      <td>
                        <div className="probability-bar">
                          <div 
                            className="probability-fill"
                            style={{ width: `${churnProbability * 100}%` }}
                          ></div>
                          <span className="probability-text">
                            {(churnProbability * 100).toFixed(1)}%
                          </span>
                        </div>
                      </td>
                      <td>
                        <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                          {riskLevel}
                        </span>
                      </td>
                      <td>
                        <span className={`prediction ${customer.Predicted_Churn === 'Yes' || customer.Predicted_Churn === 1 ? 'churn' : 'no-churn'}`}>
                          {customer.Predicted_Churn === 'Yes' || customer.Predicted_Churn === 1 ? "🚨 Churn" : "✅ Retain"}
                        </span>
                      </td>
                      <td>{formatDisplayValue(customer.Tenure, 'Tenure')}</td>
                      <td>{formatDisplayValue(customer.OrderCount, 'OrderCount')}</td>
                      <td>{formatDisplayValue(customer.CashbackAmount, 'CashbackAmount')}</td>
                      <td>{formatDisplayValue(customer.DaySinceLastOrder, 'DaySinceLastOrder')}</td>
                      <td>
                        <div className="satisfaction-score">
                          {formatDisplayValue(customer.SatisfactionScore, 'SatisfactionScore')}
                          {customer.SatisfactionScore && customer.SatisfactionScore !== '-' && (
                            <span className="score-stars">
                              {'★'.repeat(customer.SatisfactionScore)}{'☆'.repeat(5 - customer.SatisfactionScore)}
                            </span>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {filteredPredictions.length === 0 && (
          <div className="no-results">
            <p>No customers found matching your search criteria.</p>
          </div>
        )}
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📥 Download Reports</h3>
        <div className="download-options-grid">
          {/* Complete Report */}
          <div className="download-option-full">
            <h4>📊 Complete Analysis Report</h4>
            <p>Download the <strong>complete dataset</strong> with predictions for <strong>ALL {totalCustomers} customers</strong>, including churn probabilities, risk levels, and personalized retention recommendations in CSV format.</p>
            <button className="download-btn primary download-all-btn" onClick={downloadAllCustomers}>
              <span className="btn-icon">📥</span>
              Download Complete Report (All {totalCustomers} Customers)
            </button>
            <p className="download-note-small">
              <strong>Note:</strong> This will process your original CSV file using <strong>Median ML Imputation</strong> and generate a complete report with all customer predictions. Zero values and NaN are replaced with empty cells for better readability.
            </p>
          </div>
          
          {/* Risk-Specific Reports */}
          <div className="risk-specific-downloads">
            <h4>🎯 Download by Risk Level</h4>
            <p>Download specific customer segments based on their churn risk level:</p>
            
            <div className="risk-buttons-grid">
              {/* High Risk Button */}
              <div className="risk-download-option high-risk">
                <div className="risk-header">
                  <span className="risk-icon">🚨</span>
                  <div className="risk-info">
                    <h5>High Risk Customers</h5>
                    <p>{highRiskCount} customers with 70% churn probability</p>
                  </div>
                </div>
                <button 
                  className="download-btn high-risk-btn download-high-btn"
                  onClick={() => downloadRiskCustomers('high')}
                  disabled={highRiskCount === 0}
                >
                  <span className="btn-icon">📥</span>
                  Download High Risk ({highRiskCount})
                </button>
                <p className="risk-description">
                  Customers requiring immediate intervention with executive outreach and exclusive offers.
                </p>
              </div>

              {/* Medium Risk Button */}
              <div className="risk-download-option medium-risk">
                <div className="risk-header">
                  <span className="risk-icon">⚠️</span>
                  <div className="risk-info">
                    <h5>Medium Risk Customers</h5>
                    <p>{mediumRiskCount} customers with 31-70% churn probability</p>
                  </div>
                </div>
                <button 
                  className="download-btn medium-risk-btn download-medium-btn"
                  onClick={() => downloadRiskCustomers('medium')}
                  disabled={mediumRiskCount === 0}
                >
                  <span className="btn-icon">📥</span>
                  Download Medium Risk ({mediumRiskCount})
                </button>
                <p className="risk-description">
                  Customers needing proactive engagement campaigns and loyalty program enrollment.
                </p>
              </div>

              {/* Low Risk Button */}
              <div className="risk-download-option low-risk">
                <div className="risk-header">
                  <span className="risk-icon">✅</span>
                  <div className="risk-info">
                    <h5>Low Risk Customers</h5>
                    <p>{lowRiskCount} customers with ≤30% churn probability</p>
                  </div>
                </div>
                <button 
                  className="download-btn low-risk-btn download-low-btn"
                  onClick={() => downloadRiskCustomers('low')}
                  disabled={lowRiskCount === 0}
                >
                  <span className="btn-icon">📥</span>
                  Download Low Risk ({lowRiskCount})
                </button>
                <p className="risk-description">
                  Loyal customers for regular communication and upselling opportunities.
                </p>
              </div>
            </div>
          </div>
        </div>
        
        <div className="report-features">
          <h5>All Reports Include:</h5>
          <ul>
            <li>✅ Original customer data features</li>
            <li>✅ Churn probability percentages</li>
            <li>✅ Risk level classification</li>
            <li>✅ Churn prediction (Yes/No)</li>
            <li>✅ Personalized retention recommendations</li>
            <li>✅ Summary statistics and insights</li>
            <li>✅ Analysis metadata and timestamps</li>
            <li>✅ Median ML Imputation applied</li>
            <li>✅ Zero values and NaN replaced with empty cells</li>
          </ul>
        </div>
      </div>

      {/* Hidden file input for re-upload */}
      <input
        type="file"
        accept=".csv"
        id="batch-file"
        style={{ display: 'none' }}
        onChange={() => {}} // Empty handler, just for file access
      />
    </div>
  );
}

export default BatchDashboard;
